/// NUEVA LOGICA DE DESEMPAQUETADO CONSOLIDADO EN NODE-RED (BLINDADA PARA INFLUXDB)
if (msg.payload) {
    // CORRECCIÓN CRUCIAL: Si ya es un objeto lo usamos, si es texto lo parseamos
    var paquete = (typeof msg.payload === "string") ? JSON.parse(msg.payload) : msg.payload;

    var origen = paquete.procedencia || "desconocido"; 

    var temp_int = null, hum_int = null;
    var temp_ext = null, hum_ext = null;

    // 1. Desempaquetar Sensor Interior (Tuya)
    if (paquete.sensor_clima_interior && Array.isArray(paquete.sensor_clima_interior)) {
        paquete.sensor_clima_interior.forEach(function(item) {
            if (item.code === "va_temperature") temp_int = item.value / 10.0;
            if (item.code === "va_humidity") hum_int = item.value;
        });
    }

    // 2. Desempaquetar Sensor Exterior (Tuya)
    if (paquete.sensor_clima_exterior && Array.isArray(paquete.sensor_clima_exterior)) {
        paquete.sensor_clima_exterior.forEach(function(item) {
            if (item.code === "va_temperature") temp_ext = item.value / 10.0;
            if (item.code === "va_humidity") hum_ext = item.value;
        });
    }

    // 3. Extraer Variables del Vatímetro y Caudalímetro Simulado
    // Esto soporta tanto el formato antiguo (objeto anidado) como el nuevo (plano)
    var potencia = null;
    var caudal = null;

    if (paquete.vatimetro_simulado && typeof paquete.vatimetro_simulado === "object") {
        potencia = paquete.vatimetro_simulado.potencia_activa_W;
        caudal = paquete.vatimetro_simulado.caudal_agua_Lmin;
    } else {
        potencia = paquete.consumo_electrico_W !== undefined ? paquete.consumo_electrico_W : paquete.vatimetro_simulado;
        caudal = paquete.caudal_agua_Lmin !== undefined ? paquete.caudal_agua_Lmin : paquete.caudalimetro_simulado;
    }

    // 4. CREAR OBJETO DE CAMPOS LIMPIO (¡La magia para que InfluxDB no falle!)
    // Solo añadimos la variable si realmente tiene un número válido.
    var campos = {};
    if (temp_int !== null) campos.temperatura_interior = temp_int;
    if (hum_int !== null) campos.humedad_interior = hum_int;
    if (temp_ext !== null) campos.temperatura_exterior = temp_ext;
    if (hum_ext !== null) campos.humedad_exterior = hum_ext;
    if (potencia !== null && potencia !== undefined) campos.consumo_electrico_W = potencia;
    if (caudal !== null && caudal !== undefined) campos.caudal_agua_Lmin = caudal;

    // 5. Crear payload final estructurado para InfluxDB
    // Si hay al menos 1 campo válido, lo enviamos. Si no, lo descartamos.
    if (Object.keys(campos).length > 0) {
        msg.payload = [
            campos, // [ {campos_numéricos} ]
            {       // [ {etiquetas_de_texto} ]
                procedencia: origen,
                concentrador_hw: "LILYGO_T_SIM7600"
            }
        ];
        return msg;
    }
}
return null;

